+fn encode_form_body(params: &[(&str, String)]) -> String {
+    let mut body = String::new();
+    for (index, (key, value)) in params.iter().enumerate() {
+        if index > 0 {
+            body.push('&');
+        }
+        append_form_component(&mut body, key);
+        body.push('=');
+        append_form_component(&mut body, value);
+    }
+    body
