+fn append_form_component(target: &mut String, value: &str) {
+    for byte in value.bytes() {
+        match byte {
+            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'.' | b'_' | b'~' => {
+                target.push(byte as char);
+            }
+            b' ' => target.push('+'),
+            _ => {
+                let _ = std::fmt::Write::write_fmt(target, format_args!("%{byte:02X}"));
+            }
+        }
+    }
+}
