+    let data = serde_json::to_vec_pretty(state).map_err(|error| FcpError::Internal {
+        message: format!("Failed to serialize history cursor state: {error}"),
+    })?;
+
+    let tmp_name = format!(
+        ".{}-{}.tmp",
+        path.file_name()
+            .and_then(|value| value.to_str())
+            .unwrap_or("gmail-history-cursor"),
+        uuid::Uuid::new_v4()
