+    let tmp_path = path.with_file_name(tmp_name);
+    fs::write(&tmp_path, data).map_err(|error| FcpError::Internal {
+        message: format!(
+            "Failed to write temporary history cursor state {}: {error}",
+            tmp_path.display()
+        ),
+    })?;
